mapper.select:
SELECT 'ENTRY' as event_type, DATE_FORMAT(a.entry_date, '%Y-%m-%d') as event_time, CONCAT('批次: ', b.batch_code) as item_name, CONCAT('入栏，品种: ', a.breed) as detail, NULL as operator, CONCAT(IFNULL(CAST(a.birth_weight AS CHAR), '未知'), ' kg') as dosage FROM animals a LEFT JOIN batches b ON a.batch_id = b.id WHERE a.ear_tag = #{earTag}
UNION ALL
SELECT 'IMMUNIZATION' as event_type, DATE_FORMAT(ir.event_time, '%Y-%m-%d') as event_time, dv.generic_name as item_name, ir.notes as detail, ir.operator, ir.dosage FROM immunization_records ir LEFT JOIN drugs_vaccines dv ON ir.vaccine_id = dv.id WHERE ir.ear_tag = #{earTag}
UNION ALL
SELECT 'MEDICATION' as event_type, DATE_FORMAT(mr.event_time, '%Y-%m-%d') as event_time, dv.generic_name as item_name, mr.reason as detail, mr.operator, mr.dosage FROM medication_records mr LEFT JOIN drugs_vaccines dv ON mr.drug_id = dv.id WHERE mr.ear_tag = #{earTag}
UNION ALL
SELECT 'PEN_TRANSFER' as event_type, DATE_FORMAT(ptr.event_time, '%Y-%m-%d') as event_time, CONCAT(IFNULL(pf.pen_name, '初始'), ' → ', pt.pen_name) as item_name, ptr.reason as detail, NULL as operator, NULL as dosage FROM pen_transfer_records ptr LEFT JOIN pens pf ON ptr.from_pen_id = pf.id LEFT JOIN pens pt ON ptr.to_pen_id = pt.id WHERE ptr.ear_tag = #{earTag}
UNION ALL
SELECT 'SLAUGHTER' as event_type, DATE_FORMAT(sr.event_time, '%Y-%m-%d') as event_time, sr.type as item_name, CONCAT( IFNULL(sr.destination, ''), IF(sr.weight IS NOT NULL, CONCAT(' 重量: ', sr.weight, 'kg'), ''), IF(sr.price IS NOT NULL, CONCAT(' 价格: ¥', sr.price), '') ) as detail, NULL as operator, NULL as dosage FROM slaughter_records sr WHERE sr.ear_tag = #{earTag}
ORDER BY event_time
